module RefModule(datain, dataout, load, initialize, clock);
input [4:0] datain;
input load, initialize;
input clock;
output [4:0] dataout;
reg [4:0] out;
always @(posedge clock)
begin
    if(initialize)
       out <= 5'b10000;
    else if(load)
       out <= datain;
    else
       out <= 5'b0;
end
wire __dataout_tmp = out;
assign dataout = __dataout_tmp;
endmodule
